/* techniques q04 (73 mục) — cập nhật 2026-06-15, bù 4 công pháp/thần thông có tên thật (Thuật Thần Đạo, Tế đan luyện thuật, U Minh nhãn, Lò luyện ý cảnh) - gop trung 2026-06-24 - gop trung 2026-07-10 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q04"]=window.__LIBQ["tien-nghich"]["q04"]||{};window.__LIBQ["tien-nghich"]["q04"]["techniques"]={"updatedAt":"2026-06-14","chapterRange":"c0001-c0390","count":72,"techniques":[{"id":"thien-quy-suu-than-thuat","name":"Thiên Quỷ Sưu thần thuật","loai":"than-thong","loaiLabel":"Thần thông","he":"Hỏa Phần quốc","phamCap":"Cao cấp — thanh niên thi khô Anh Biến kỳ","hePhai":null,"soHuu":["thanh-nien-chien-than-dien-chu-vo-kiem"],"blurb":"Thần thông của tu sĩ Hỏa Phần quốc: phân thân thần thức thành vô số phân thân nhỏ hợp lực nhau, tốc độ và uy lực tăng vọt theo số lượng phân thân. Tu sĩ Hỏa Phần quốc Anh Biến kỳ phóng ra ngay cả khi chỉ còn 3 thành công lực trong trạng thái thi khô ba nghìn năm.","detail":"Thiên Quỷ Sưu thần thuật lần đầu xuất hiện khi thanh niên thi khô Hỏa Phần quốc đang trong trạng thái gần mất ý thức hoàn toàn (@c0208). Cơ chế: vô số phân thân thần thức hợp lực tăng tốc — tương tự cách hiểu VL về Mặc Lưu Hóa Thần thuật, nhưng áp dụng theo kiểu khác. Sau khi VL thu được vỏ kiếm cổ thứ hai, Vương Lâm suy nghĩ về cơ chế này (@c0210).","nguon":["@c0208","@c0210"]},{"id":"du-linh-thuat","name":"Dự linh thuật","loai":"than-thong","loaiLabel":"Thần thông","he":"Phác Nam Tử","phamCap":"Nguyên Anh hậu kỳ","hePhai":null,"soHuu":["dang-hoa-nguyen"],"blurb":"Thần thông do Phác Nam Tử truyền thụ cho Đằng Hóa Nguyên. Cho phép người dùng cảm nhận trước một số biến cố hoặc nguy hiểm. Đằng Hóa Nguyên có được sau khi Phác Nam Tử đạt Nguyên Anh hậu kỳ năm ngoái (@c0210) và trao lại.","detail":"Dự linh thuật được đề cập khi VL nhận ra Đằng Hóa Nguyên đã đột phá Nguyên Anh hậu kỳ (@c0210) và Phác Nam Tử truyền thần thông này. Không có thêm chi tiết cơ chế từ nguyên tác Ch.201-210.","nguon":["@c0210"]},{"id":"than-thong-goi-hon","name":"Thần thông gọi hồn (Đồ Ti)","loai":"than-thong","loaiLabel":"Thần thông cổ thần — triệu hồn","phamCap":"Cổ thần cấp — học từ ký ức Đồ Ti","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông học từ ký ức cổ thần Đồ Ti: hô 'Hồn phách [tên], hiện!' — triệu hồn phách người đã chết từ cõi hư vô về trong nửa nén hương. Hồn phách triệu về không có ký ức, chỉ có bản năng liên huyết thống — dùng để dò định vị những người mang huyết thống của đối tượng. Vương Lâm dùng triệu hồn phách Đằng Lệ để cảm ứng và định vị toàn bộ huyết thống Đằng gia khắp Triệu quốc trước khi mở cuộc tru diệt (@c0211).","detail":"Khi thi triển, hư ảnh pho tượng viễn cổ ma thần (Đồ Ti) hiện ra sau lưng Vương Lâm, nuốt máu tươi rồi phun ra thanh mang. Cơ chế định vị huyết thống: nhờ cảm ứng hồn phách Đằng Lệ kết hợp thần thức quét toàn Triệu quốc, mỗi người mang tia huyết thống Đằng gia (trực hệ, chi thứ, con gái/con dâu sinh con trai) đều hiện thành một điểm sáng trong thần thức — cho phép VL định vị tận gốc toàn bộ dòng họ Đằng để diệt tộc. Thần thông này KHÁC với thôn hồn (thu hồn phách luyện du hồn); đây là triệu hồn từ cõi hư vô về làm 'công cụ' rồi hoàn trả, không lưu giữ.","nguon":["@c0211"]},{"id":"thong-thien-thuat-cu-ma-toc","name":"Thông thiên thuật (Cự Ma tộc)","loai":"than-thong","loaiLabel":"Thần thông cổ đại — Cự Ma tộc","phamCap":"Cực cao — cần cổ thần lực làm chất dẫn","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông cổ đại của Cự Ma tộc, thi triển bằng ngôn ngữ chú ngữ cổ thần và cần một lượng cổ thần lực (máu cổ thần) làm chất dẫn. Khi phát động, triệu hiện hư ảnh khổng lồ 'đầu đội trời chân đạp đất' tạo từ linh lực — tiêu tốn 3/5 linh mạch Triệu quốc khi Vương Lâm lần đầu dùng. Hư ảnh một vung tay hạ Đằng Nhất từ xa tức thì (@c0219).","detail":"Vương Lâm biết nhiều phép thuật ngôn ngữ cổ thần từ ký ức Đồ Ti nhưng thường không dùng được vì thiếu 'truyền thừa lực lượng cổ thần'; lần này dùng được nhờ nửa cục máu vàng (chứa tia máu cổ thần) đoạt từ Đằng Nhất phun ra. Cơ chế: dùng cổ thần lực trong cục máu làm chất dẫn, đọc chú ngữ cổ thần — cục máu hóa thành ký hiệu cổ, kim quang giáng xuống, triệu hiện thân ảnh khổng lồ. Vì máu cổ thần quá ít nên thân ảnh chỉ duy trì trạng thái hư ảo (KHÔNG phải hình thật). Hao tổn khổng lồ: hút sạch 3/5 linh mạch Triệu quốc, 2/5 còn lại linh lực tiêu tan — toàn bộ Nguyên Anh tu sĩ trở lên ở Triệu quốc cảm nhận dị thường; cao thủ Thông Thiên Tháp nhận diện đó là thông thiên thuật Cự Ma tộc. Vương Lâm thi triển lần đầu tại trận Hắc Nê Đàm để hạ Đằng Nhất @c0219.","nguon":["@c0219"]},{"id":"y-canh","name":"Ý cảnh","loai":"khai-niem","loaiLabel":"Khái niệm tu luyện","phamCap":"Điều kiện đột phá Hóa Thần kỳ","hePhai":null,"soHuu":[],"blurb":"Khái niệm then chốt để đột phá Nguyên Anh kỳ lên Hóa Thần kỳ. Mỗi Hóa Thần tu sĩ đều có ý cảnh riêng ẩn trong pháp thuật/thần thông, phản ánh thế giới quan và cảm ngộ thiên đạo của bản thân. Tu sĩ muốn Hóa Thần phải lĩnh ngộ ý cảnh — tức là cảm nhận và tìm ra ý cảnh phù hợp với bản thân. Ba ý cảnh VL lĩnh ngộ từ Bạch Vân Tông: tuyệt tình (trung niên văn sĩ), ấm áp/hư vô (lão bà), tuế nguyệt (lão giả thanh sam).","detail":"Ý cảnh không phải công pháp có thể truyền thụ trực tiếp — tu sĩ chỉ thi triển, kẻ quan sát tự cảm ngộ. Lão nhân Anh Biến kỳ giải thích: mỗi ý cảnh ứng với con đường hóa phàm khác nhau. Ý cảnh tuế nguyệt của lão giả thanh sam được lão nhân đánh giá: 'nếu đạt Vấn Đỉnh sẽ nghịch thiên'. Chu Võ Thái hóa phàm theo con đường tình thầy trò — ý cảnh sẽ là bi thương tột cùng khi tự tay giết đệ tử. Vương Lâm tính đến Ch.240 vẫn chưa xác định được ý cảnh của bản thân.","nguon":["@c0234","@c0235","@c0236","@c0239"]},{"id":"tue-nguyet-y-canh","name":"Tuế Nguyệt ý cảnh","loai":"y-canh","loaiLabel":"Ý cảnh Hóa Thần — Tuế Nguyệt","he":null,"phamCap":"Ý cảnh Hóa Thần — đánh giá 'nếu đạt Vấn Đỉnh sẽ nghịch thiên'","hePhai":"Bạch Vân Tông","soHuu":["vuong-lam"],"blurb":"Ý cảnh của lão giả thanh sam Bạch Vân Tông — khắc họa sức nặng và chiều sâu của thời gian. VL lĩnh ngộ sau khi lão giả thi triển tượng gỗ lão già áo xanh. Lão nhân Anh Biến kỳ đánh giá: 'nếu đạt Vấn Đỉnh sẽ nghịch thiên'. (+) Ý cảnh Vương Lâm học được từ một tu sĩ ở Chu Tước Tinh năm xưa, tự thân bắt chước cầm giữ tu vi được vài phần. [CAN-SOAT-GOP]","detail":"VL lĩnh ngộ ý cảnh tuế nguyệt từ lão giả thanh sam Bạch Vân Tông (@c0236). Sau đó VL tự điêu khắc tượng gỗ lão già áo xanh thể hiện ý cảnh này — thành công ở @c0241, đạt mức ngang pháp bảo Nguyên Anh kỳ cao nhất. Ý cảnh tuế nguyệt là một trong ba ý cảnh VL lĩnh ngộ (tuyệt tình, ấm áp/hư vô, tuế nguyệt) — tất cả đều là vật liệu cảm ngộ cho ý cảnh Sinh Tử của chính VL sau này.","nguon":["@c0236","@c0241","@c0617"]},{"id":"y-canh-sinh-tu","name":"Ý cảnh Sinh Tử","loai":"y-canh","loaiLabel":"Ý cảnh Hóa Thần — Sinh Tử","he":null,"phamCap":"Ý cảnh Hóa Thần — tâm cảnh viên mãn, sẵn sàng đột phá","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Ý cảnh đặc hữu của Vương Lâm: kết hợp 400 năm giết chóc (chữ Tử) với 30 năm hóa phàm bình dị (chữ Sinh), cộng với cảm ngộ thiên đạo luân hồi. Tâm cảnh đạt mức 'Muốn núi là thấy núi, muốn nước là thấy nước' — có thể tự điều khiển cấp độ tu vi.","detail":"Hình thành qua hai giai đoạn: (1) VL điêu khắc từng vong hồn bị giết suốt 400 năm tu đạo, đắm chìm hoàn toàn vào ký ức — kết hợp ý nghĩa chữ Tử (sát ký 400 năm) và chữ Sinh (30 năm phàm nhân); (2) kết hợp cảm ngộ thiên đạo luân hồi từ @c0241 — đạt ý cảnh Sinh Tử @c0247. Đây là nền tảng để ngưng tụ Hắc Ấn chữ Tử @c0248 và điều kiện đột phá Hóa Thần. Tiếp tục đào sâu: @c0258 VL ngộ thêm thế nào là sinh thế nào là tử (giai đoạn 'nhin núi không phải là núi'). @c0259 Mặc Trí giảng 'cơn mưa sinh từ trời, rơi xuống đất mà chết — khoảng giữa là nhân sinh' → VL chấn động, bước tiến then chốt. @c0260 lĩnh ngộ hoàn toàn, làm nền cho con đường Đạo Cổ thần.","nguon":["@c0247","@c0248","@c0258","@c0259","@c0260","@c0381","@c0382"]},{"id":"hac-an-chu-tu","name":"Hắc Ấn chữ Tử","loai":"than-thong","loaiLabel":"Thần thông — ngưng tụ sát ký","he":null,"phamCap":"Tự sáng tạo — tích lũy 400 năm","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Hình vuông cỡ bàn tay, khắc hình người không mặt mũi; ngưng tụ từ vô số tượng gỗ điêu khắc vong hồn + huyết cầu sát khí 400 năm giết chóc. Dung nhập vào Nguyên Anh Vương Lâm, mang toàn bộ ý nghĩa chữ Tử (sát ký).","detail":"Hình thành sau khi VL đạt ý cảnh Sinh Tử: dòng chảy đen từ vô số tượng gỗ + huyết cầu sát khí ngưng tụ thành Hắc Ấn hình vuông. Dung nhập vào Nguyên Anh VL, đánh dấu kết thúc giai đoạn hóa phàm. Công năng cụ thể chưa được thi triển trong nguyên tác tính đến c0250.","nguon":["@c0247","@c0248"]},{"id":"bang-tuyet-quyet","name":"Băng Tuyết quyết","loai":"cong-phap","loaiLabel":"Công pháp — tà đạo nghịch thiên","he":"Băng tuyết — hàn hệ","capBac":"Không rõ phẩm cấp","hePhai":"Tuyết Vực Quốc","nguoiDung":["Tuyết Vực Quốc (tu sĩ)"],"blurb":"Công pháp cốt lõi của Tuyết Vực Quốc — luyện tâm bằng băng tuyết: dùng băng thay đổi xương cốt, dùng tuyết ngưng tâm, tạo thành 'băng tuyết chi hồn'. Kết quả: tâm trong như băng, đạt mức 'tùy tâm sở dục' với công pháp; có thể ngưng luyện tinh tinh khí khi nhập trần. VL nhận định: NGHỊCH THIÊN — không phải chính đạo.","detail":"Cơ chế: băng thay đổi xương cốt, tuyết ngưng tâm → băng tuyết chi hồn → tâm trong như băng. Hiệu quả: tu sĩ Tuyết Vực đạt 'tùy tâm sở dục' với công pháp (trình độ tinh thông cao); ngưng luyện tinh tinh khí khi nhập trần (xuống như người bình thường). Cũng giải thích vì sao khôi lỗi Tuyết Vực cần duy trì bằng tuyết kinh mạch (49 tuyết kinh mạch = tương đương Kết Đan trung kỳ; 81 = Nguyên Anh kỳ). VL nghiên cứu @c0258 nhưng không tu luyện — dùng nguyên lý để sáng tạo huyết kinh mạch. So sánh: tương tự Lục Dục Ma Quan (khác cách nhưng cùng kết quả). VL đánh giá: nghịch thiên, không phải chính đạo.","nguon":["@c0258"]},{"id":"huyet-kinh-mach","name":"Huyết kinh mạch","loai":"than-thong","loaiLabel":"Thần thông — tự sáng tạo","he":"Huyết — Sinh Tử ý cảnh","capBac":"Tự sáng tạo","hePhai":null,"nguoiDung":["vuong-lam"],"blurb":"Biến thể của tuyết kinh mạch do Vương Lâm tự sáng tạo — thay tuyết bằng huyết (máu tươi), kết hợp ý cảnh Sinh Tử để điều khiển khôi lỗi. Mục đích: đạt được hiệu quả tương đương tuyết kinh mạch nhưng không cần tu luyện Băng Tuyết quyết nghịch thiên.","detail":"VL nghiên cứu Băng Tuyết quyết và cơ chế tuyết kinh mạch @c0258, quyết không tu luyện nghịch thiên nhưng mô phỏng nguyên lý: thay tuyết bằng huyết (máu tươi), kết hợp ý cảnh Sinh Tử để điều khiển (máu = Sinh, sát ký = Tử). Kết quả: có thể điều khiển khôi lỗi theo cách tương tự tuyết kinh mạch. Chi tiết công năng đầy đủ chưa được triển khai trong nguyên tác tính đến c0260.","nguon":["@c0258"]},{"id":"si-y","name":"Si Ý","loai":"y-canh","loaiLabel":"Ý cảnh — tình si cực hạn","he":"Chu Dật","phamCap":"Anh Biến kỳ bộc phát khí thế Trảm Tiên","hePhai":"Ngũ Hành Tông","soHuu":["chu-dat","sat-ho"],"blurb":"Ý cảnh của Chu Dật — tình si tích lũy suốt ngàn năm, đạt cực điểm thành 'Si vì tình → cực vì Ý'. Chu Dật ép Sất Hổ làm phân thân để tiếp nhận Si Ý; khi nhập vào người Sất Hổ, Si Ý bộc phát khí thế Hóa Thần kỳ Trảm Tiên.","detail":"Cơ chế truyền thừa đặc biệt: Chu Dật ép người khác làm phân thân để tiếp nhận ý cảnh — không phải tự cảm ngộ. Sất Hổ hấp thu Si Ý @c0289-@c0290, phân thân Si Ý xuất hiện phát khí thế Hóa Thần kỳ Trảm Tiên, đủ sức đối đầu lão đầu Thi Âm Tông Anh Biến kỳ đang phụ thể Hồng Điệp.","nguon":["@c0289","@c0290"]},{"id":"am-ba-linh-giap","name":"Âm Ba Linh Giáp","loai":"than-thong","loaiLabel":"Thần thông — công pháp tự sáng tạo","he":null,"phamCap":"Hóa Thần kỳ — ngay cả Anh Biến kỳ cũng thấy khó phá","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Khải giáp tự sáng tạo của VL — dùng 2 chuông Linh Đang vỡ (âm ba) ngưng tụ thành khải giáp phòng thủ cực mạnh. Lần đầu triển khai trong trận chiến với Liêu Phàm @c0332.","detail":"VL trong trận chiến với Liêu Phàm đập vỡ 2 chuông Linh Đang (giữ lại 1), dùng âm ba tán ra ngưng tụ thành khải giáp bao phủ thân thể — Liêu Phàm nhận xét ngay cả Anh Biến kỳ cũng phải sợ. Cơ chế: âm ba từ chuông Linh Đang (thượng cổ linh khí) ngưng kết thành lớp bảo vệ ôm lấy cơ thể. Kết hợp với Băng Viêm (Hoàng Tuyền Băng Viêm) làm chân đế — toàn thân phát ra khí tức của Hoàng Tuyền Băng Viêm và âm ba. Tên tự đặt: 'Âm Ba Linh Giáp'. @c0332","nguon":["@c0332"]},{"id":"phan-than-bien","name":"Phân Thần Biến","loai":"than-thong","loaiLabel":"Thần thông — phân lục nguyên","he":"Hồng Điệp","phamCap":"Hóa Thần hậu kỳ","hePhai":"Thiên Ngọc tông / Chu Tước quốc","soHuu":["hong-diep"],"blurb":"Thần thông của Hồng Điệp — phân chia thân thể thành 6 phần (lục nguyên), mỗi phần hóa thành một nữ tử áo đỏ (nụ hoa đỏ hóa hình). Khi thu hồi 6 phần nhập thân lại, phía sau lộ 6 hư ảnh đỏ lung linh (lục nguyên hợp nhất). @c0337","detail":"Từ người Hồng Điệp mọc ra các nụ hoa đỏ, nở thành 6 nữ tử áo đỏ — mỗi người mang một phần nguyên lực. Lục nguyên hợp nhất: 6 phần thu hồi tạo ra 6 hư ảnh màu đỏ lung linh kỳ diệu. Khi gặp Thiên Kiếp — Hồng Điệp hy sinh cả 6 hư ảnh để chống tia sét @c0337. Công Tôn Phá nhận ra 'Lục nguyên hợp nhất!' khi quan sát trận chiến.","nguon":["@c0337"]},{"id":"tuyet-tinh-y-canh","name":"Tuyệt Tình Ý Cảnh","loai":"y-canh","loaiLabel":"Ý cảnh Hóa Thần — Tuyệt Tình","he":"Hồng Điệp","phamCap":"Hóa Thần hậu kỳ — tối đỉnh (7 bước hoàn chỉnh)","hePhai":"Thiên Ngọc tông / Chu Tước quốc","soHuu":["hong-diep"],"blurb":"Ý cảnh cực đỉnh của Hồng Điệp — thế giới không tình không nghĩa, mỗi bước tạo một thế giới tuyệt tình riêng biệt; 7 bước = 7 tầng thế giới tuyệt tình chồng lên. Lần đầu triển khai đầy đủ tại trận chiến VL @c0339. Sau đó bị Kiền Phong cướp đoạt @c0340.","detail":"7 bước hoàn chỉnh: mỗi bước Hồng Điệp tạo một thế giới nhỏ tuyệt tình, chồng lên tầng trước (tầng 7 bủa vây VL bằng 7 thế giới tuyệt tình). VL nhận xét: mỗi tầng đều là cực hạn — tầng 1 đã là cực hạn, tầng 7 là đỉnh. Bị Sinh Tử Luân Hồi Ý Cảnh của VL phá vỡ @c0339. Sau trận — bị Kiền Phong (lệnh của lão tổ cấm địa) đoạt mất cùng tiên thiên tứ linh @c0340.","nguon":["@c0339","@c0340"]},{"id":"sinh-tu-luan-hoi-y-canh","name":"Sinh Tử Luân Hồi Ý Cảnh","loai":"y-canh","loaiLabel":"Ý cảnh Hóa Thần — Sinh Tử Luân Hồi","he":"Vương Lâm","phamCap":"Hóa Thần trung kỳ — thức tỉnh lần đầu","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Ý cảnh đỉnh cao của VL — kết hợp ý cảnh Sinh Tử với luân hồi (thiên đạo quan). Khi triển khai: xé rách bầu trời, mở bức tranh sơn thủy đen trắng khổng lồ; hai đạo khí đen trắng giao hòa thành bụi khí luân hồi hóa ngón tay khổng lồ chặn phân thân Hồng Điệp. Phản luận: tuệ kiếm không cắt đứt được luân hồi. Phân thân thất bại, tản ra biến mất @c0339.","detail":"Thức tỉnh lần đầu trong trận chiến ý cảnh với Hồng Điệp @c0339 — khi Hồng Điệp dùng phân thân triển khai tuyệt tình ý cảnh (7 bước: dẫn tình → thân tình → tình yêu → hận ý → cảm ngộ → tuệ kiếm → tuyệt tình), VL đáp trả: khẩu quyết 'Luân hồi chi hạ, sinh tử thiên đạo', xé rách bầu trời, bức tranh sơn thủy đen trắng khổng lồ hiện ra trong khe nứt. Bức tranh phát hai đạo khí đen trắng giao hòa thành bụi khí luân hồi, ngưng tụ thành ngón tay khổng lồ chặn phân thân Hồng Điệp. Phân thân than 'Đáng tiếc' rồi tản ra biến mất. Nền tảng: ý cảnh Sinh Tử đã đạt từ @c0247 + cảm ngộ thiên đạo luân hồi suốt hành trình tu luyện. Bức tranh cùng loại đã dùng bảo hộ nguyên anh LMU @c0313 — lần này là phản kích ý cảnh.","nguon":["@c0339","@c0371","@c0380","@c0381"]},{"id":"phong-ma-can-khon-tran","name":"Phong Ma Khôn Càn Trận","loai":"tran-phap","loaiLabel":"Trận pháp — phong tỏa không gian","he":"Cự Ma tộc","phamCap":"Anh Biến kỳ (lão tổ Cự Ma tộc bố trí)","hePhai":"Cự Ma tộc","soHuu":["lao-to-cu-ma-toc"],"blurb":"Trận pháp đặc thù của Cự Ma tộc — phong tỏa hoàn toàn không gian trong phạm vi, khiến mục tiêu không thể thuấn di hay xé không gian thoát. Lão tổ Cự Ma tộc bố trí để vây VL tại Chu Tước tinh. Bị Tôn Thái đột nhập bằng Lôi Chi Ý Cảnh (Thiên Lôi đen) xuyên phá. @c0343","detail":"Phong tỏa hoàn toàn: tu sĩ trong trận không thể sử dụng thuấn di, không thể xé không gian — các kỹ thuật không gian đều bị triệt tiêu. Lão tổ Cự Ma tộc (Anh Biến kỳ cưỡng ép) bố trí để kẹt VL không nơi trốn thoát. Tôn Thái xuyên phá bằng Lôi Chi Ý Cảnh @c0343.","nguon":["@c0343"]},{"id":"y-canh-tra-huong","name":"Ý Cảnh Trà Hương","loai":"y-canh","loaiLabel":"Ý cảnh Anh Biến — đại thành","he":"Lý Nguyên Phong","phamCap":"Anh Biến kỳ (đại thành ý cảnh)","hePhai":"Băng Tuyết Thần Điện","soHuu":["tong-chu-bang-tuyet-than-dien"],"blurb":"Ý cảnh đặc thù của Lý Nguyên Phong (tông chủ Băng Tuyết Thần Điện) — đại thành ý cảnh cấp Anh Biến kỳ. Ẩn dấu lá trà tiêu hao thân thể + nguyên thần đối phương từ bên trong. Triển khai trong trận chiến với Tôn Thái tại Chu Tước tinh @c0343.","detail":"Cơ chế: Lý Nguyên Phong dùng ý cảnh trà hương ẩn dấu bên trong đòn tấn công; khi tiếp xúc, lá trà thấm vào thân thể đối phương tiêu hao thân thể + nguyên thần liên tục. Bị Tôn Thái (Anh Biến trung kỳ) phóng Thiên Lôi đen đuổi Lý Nguyên Phong rút lui @c0344.","nguon":["@c0343","@c0344"]},{"id":"loi-chi-y-canh","name":"Lôi Chi Ý Cảnh","loai":"y-canh","loaiLabel":"Ý cảnh Anh Biến — Thiên Lôi","he":"Tôn Thái","phamCap":"Anh Biến trung kỳ (cảm ngộ ở Thiên Lôi Tinh)","hePhai":"Thi Âm Tông","soHuu":["lao-dau-thi-am-tong"],"blurb":"Ý cảnh đỉnh cao Tôn Thái cảm ngộ khi bế quan ở Thiên Lôi Tinh — triệu được Thiên Lôi đen (đen tuyền, uy lực kinh thiên). Lần đầu dùng để xuyên phá Phong Ma Khôn Càn Trận cứu VL @c0343; sau đó phóng hắc lôi đuổi Lý Nguyên Phong rút lui @c0344.","detail":"Cảm ngộ trong thời gian bế quan tại Thiên Lôi Tinh (tinh cầu sấm sét). Thiên Lôi đen: màu đen tuyền, khác Thiên Lôi bình thường (trắng/vàng) — uy lực mạnh hơn đáng kể. Dùng xuyên trận pháp Phong Ma Khôn Càn Trận của Cự Ma tộc; sau đó phóng thẳng tại Lý Nguyên Phong — tông chủ Băng Tuyết Thần Điện phải rút lui về Tuyết Vực @c0344.","nguon":["@c0343","@c0344"]},{"id":"tan-anh-cam-che","name":"Tàn Ảnh Cấm Chế","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Độc môn VL","phamCap":"Cấm chế độc môn, không rõ nguồn gốc","hePhai":"Không rõ","soHuu":["vuong-lam"],"blurb":"Thần thông cấm chế độc môn của Vương Lâm. Khi thi triển, tàn ảnh xuất hiện bay quanh thân; quát 'Phá!' tàn ảnh bay ra bám vào mục tiêu, nối tiếp nhau như bàn tay dài thâm nhập vào bên trong. Dùng phá cấm chế, tảng đá phong động phủ @c0357; tấn công thượng cổ hồn cấm trong linh mạch @c0358.","detail":"Dùng tay bấm quyết → tàn ảnh xuất hiện bay quanh thân → quát 'Phá!' → tàn ảnh bay ra bám vào mục tiêu, nối tiếp nhau như bàn tay dài thâm nhập vào bên trong. Hiệu quả: phá vỡ cấm chế thông thường (@c0357 — phá sập cấm chế + tảng đá bịt cửa động phủ); tấn công thượng cổ hồn cấm nhưng bị phản kích bằng công kích linh hồn (@c0358 — nguyên thần VL đau đớn, phải rút lui). Tàn ảnh cũng dán được lên thân yêu thú hồn cấm, loé sáng khi bị hút lại (@c0358).","nguon":["@c0351","@c0357","@c0358"]},{"id":"luyen-hon-thuat-hon-tuyen","name":"Luyện Hồn Thuật / Hồn Tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phiên thuật","phamCap":"Luyện Hồn Tông (tam pháp nhánh 1)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Công pháp/thần thông nhánh Luyện Hồn của Luyện Hồn Tông — luyện hóa tử hồn phong ấn trong Hồn Phiên, khiến hồn phách không tiêu tan mà dần lớn mạnh. Thành tựu cao nhất là Hồn Tuyền: lốc xoáy hút toàn bộ hồn phách xung quanh. VL là người thứ 3 trong đệ tử Luyện Hồn Phong luyện ra Hồn Tuyền (chỉ mất 3 tháng) @c0357-@c0359.","detail":"Luyện hồn (nhánh 1 Hồn Phiên tam pháp): luyện hóa tử hồn, phong ấn trong Hồn Phiên, dùng phương pháp đặc thù khiến không tiêu tan mà dần lớn mạnh. Thành tựu đỉnh cao = Hồn Tuyền: tạo lốc xoáy hút toàn bộ hồn phách xung quanh. Giới hạn: hồn phách mang khí tức Nguyên Anh có thể tự thoát lực hút, cần dùng trảo cách không bắt riêng. VL tu luyện tại linh mạch Luyện Hồn Phong — nương áp lực linh mạch tu vi tăng mạnh, đột phá Nguyên Anh trong 3 tháng. Kết hợp với tàn ảnh cấm chế và Thiên Hồn Phiên Huyễn Ảnh (@c0357-@c0359).","nguon":["@c0357","@c0358","@c0359"]},{"id":"thien-hon-phien-huyen-anh","name":"Thiên Hồn Phiên Huyễn Ảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông cấp cao — Hồn phiên","phamCap":"Thiên cấp (Luyện Hồn Tông)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Thần thông cấp cao liên quan hồn phiên — VL thi triển khi đối mặt Quách Đông Kiện: hắc khí từ ánh mặt trời chiếu lên người tản mát ra, ngưng tụ phía sau lưng thành cái đầu lâu thật lớn. Quách Đông Kiện nhận ra tên gọi ngay, đại biến sắc mặt @c0358.","detail":"Cơ chế: ánh mặt trời chiếu lên người VL tản hắc khí, ngưng tụ phía sau lưng thành một cái đầu lâu khổng lồ trống rỗng. Thị giác uy hiếp lớn — ngay cả tu sĩ Nguyên Anh sơ kỳ (Quách Đông Kiện) nhận ra tên gọi và tái nhợt lùi lại. Là thần thông cấp cao, VL học được trong quá trình tu Luyện Hồn Thuật tại Luyện Hồn Tông.","nguon":["@c0358"]},{"id":"thuong-co-hon-cam","name":"Thượng Cổ Hồn Cấm","cn":"","loai":"cam-che","loaiLabel":"Cấm chế — Thượng cổ","phamCap":"Loại cấm chế hiếm gặp nhất (thượng cổ)","hePhai":"Thượng cổ","soHuu":[],"blurb":"Loại cấm chế ít gặp nhất trong thượng cổ cấm chế. Khác cấm chế bình thường (vật chết, cần chìa khóa/phương pháp mở cố định): hồn cấm là sinh vật sống — toàn bộ cấm chế chính là một đạo hồn phách tồn tại dưới trạng thái cấm chế. Phản kích bằng công kích linh hồn, ngưng tụ thành yêu thú khi bị kích. Xuất hiện trong linh mạch Luyện Hồn Phong bảo vệ Kim sắc Hồn Kỳ @c0358.","detail":"Đặc điểm: (1) bản thân là hồn phách sống, không phải vật thể chết; (2) có thể cản trở thần thức thâm nhập; (3) khi bị tấn công phản kích bằng tiếng rít gào chứa ý cảnh cáo — công kích linh hồn gây đau nguyên thần; (4) có thể ngưng tụ hồn phách thành yêu thú hữu hình (hai sừng, toàn thân sương mù + tơ đen) để tấn công. Hồn cấm trong linh mạch Luyện Hồn Phong: hấp thu linh lực từ linh mạch dưới dạng tơ để nuôi dưỡng kim sắc tiểu kỳ bên trong. VL dùng Tàn ảnh cấm chế tấn công nhưng bị phản kích đau nguyên thần (@c0358).","nguon":["@c0358"]},{"id":"hon-phien-tam-phap","name":"Hồn Phiên Tam Pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp — Hồn phiên","phamCap":"Chân pháp Luyện Hồn Tông (3 nhánh)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Phương pháp chân chính Luyện Hồn Tông chia làm 3 nhánh tương ứng 3 đại phong: (1) Luyện hồn — luyện hóa tử hồn phong ấn, khiến dần lớn mạnh; (2) Trừu phách — rút sinh hồn từ cơ thể sống rồi phong ấn thao khống; (3) Toả thần — chưa rõ. VL thu thập 1/3 phương pháp từ ngọc giản đen @c0357, nghiên cứu hệ thống phân cấp Hồn Phiên từ Luyện Hồn ngọc giản @c0359.","detail":"Ba nhánh (tam pháp): (1) Luyện hồn — luyện hóa tử hồn, phong ấn trong Hồn Phiên, dùng phương pháp đặc thù khiến không tiêu tan mà dần lớn mạnh; (2) Trừu phách — từ cơ thể sống rút ra sinh hồn rồi phong ấn thao khống (không thể luyện hóa tử phách); (3) Toả thần — VL không có gì đối chiếu, chưa đoán được. Phân cấp Hồn Phiên theo số hồn phách: Thập / Bách / Thiên / Vạn. Thập và Bách thuộc cực kỳ tầm thường. Từ Thiên Hồn Phiên trở lên mới có thần thông — cần chủ hồn (mạnh hơn tổng tất cả hồn phách cộng lại). Bách Hồn Phiên tối đa 999 hồn phách nhưng thiếu chủ hồn nên không thành Thiên. Phương pháp toàn bộ chỉ có 10 ngọc giản — đệ tử phải tự đi cướp đoạt (@c0357-@c0359).","nguon":["@c0357","@c0359","@c0389"]},{"id":"thien-huyen-vo-tinh-dao","name":"Thiên Huyễn Vô Tình Đạo","cn":"","loai":"cong-phap","loaiLabel":"Công pháp — Đạo tâm","phamCap":"Cao (dành cho tu sĩ cấp cao)","hePhai":"Chu Tước Tử (đệ nhất nhân Chu Tước tinh)","soHuu":["lieu-mi"],"blurb":"Đạo mà Liễu Mi tu luyện theo chỉ điểm của sư phụ Chu Tước Tử. Bên ngoài có thể biến ảo hết thảy biểu tượng hữu hình (tạo vẻ hữu tình), chỉ có nội tâm là vô tình. Dùng trong nhiệm vụ 'lưu thân ảnh trong đạo tâm' đối phương — VL nhìn thấu bản chất nhờ so sánh biểu tình hôn mê của Hứa Vân và Lưu Vi @c0359. (+) Phương pháp tu luyện thần thông của Huyễn gia, là bản chất của ‘Thiên Huyễn thánh’, ghi trong ngọc giản của người Huyễn gia chết bốn năm trước. [CAN-SOAT-GOP] (+) Thiên Huyễn Vô Tình đạo là đạo pháp Liễu Mi tu luyện. Công pháp này khiến nàng nhiều khi không phân rõ vô tình hay hữu tình mới là bản thân mình. [CAN-SOAT-GOP]","detail":"Nguyên lý: bên ngoài biến ảo tất cả biểu hiện hữu hình để che dấu nội tâm vô tình tuyệt đối. Mục đích thực chiến: khiến đối phương nhớ tới mình (lưu thân ảnh trong đạo tâm), từ đó dẫn tới chiến đấu đạo tâm — người trong đạo tâm đối phương có hình ảnh lớn hơn thì thắng. Điểm yếu: VL phát hiện khi so sánh biểu tình hôn mê của hai người khác — nội tâm thật lộ ra khi mất đề phòng. Liễu Mi nhận định: VL không thể thắng cuộc chiến đạo tâm trừ phi đạo tâm nàng cũng có hình bóng hắn (@c0359).","nguon":["@c0359","@c0628","@c0643"],"aliases":["#thien-huyen-vo-tinh-dao-c0628"]},{"id":"thuat-truu-phach","name":"Thuật Trừu Phách","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phách","phamCap":"Chân pháp Trừu Phách phong (Luyện Hồn Tông)","hePhai":"Luyện Hồn Tông — Trừu Phách phong","soHuu":["vuong-lam"],"blurb":"Phương pháp rút hồn phách từ cơ thể kẻ khác, gồm 3 thần thông: Định Thần (tăng xác suất thành công), Dẫn Hồn (rút sinh hồn từ cơ thể sống), Tự Cổ (biến sinh hồn thành Cổ độc vật). VL học từ ngọc giản hồng sắc đổi với Tô Kim Thế. Thực chiến: điểm ngón tay vào khoảng không, đạo linh quang bay vào mi tâm đối phương, rút hồn phách ra — hồn phách Anh Biến kỳ hiện thành luồng sáng màu vàng, thân thể mục tiêu khô héo.","detail":"Ba thần thông: (1) Định Thần — thuật căn bản, tăng xác suất Trừu Phách thành công, đặc biệt khi đối phương ở trạng thái bất lợi. (2) Dẫn Hồn — pháp thuật chính thức, rút sinh hồn ra từ cơ thể người sống; uy lực phụ thuộc chênh lệch tu vi và trạng thái đối phương. (3) Tự Cổ — ác độc nhất, biến sinh hồn thành Cổ (độc vật); luyện hóa lâu dài tạo Cổ hồn thú tương đương Kết Đan kỳ. Lịch sử: đệ tử phản phái Trừu Phách phong dùng Tự Cổ biến tướng, luyện hơn mười vạn Lục đan, tu tới Hóa Thần, lập Đan Ma đạo. Ngọc giản hồng sắc ghi chép toàn bộ phương pháp + 3 thần thông. Tô Kim Thế lấy từ Luyện Hồn phong nhiều năm trước; đổi cho VL lấy 300 tử hồn (@c0362). VL thực chiến dùng Dẫn Hồn rút hồn phách Anh Biến kỳ Lý Nguyên Phong (@c0368).","nguon":["@c0362","@c0368"]},{"id":"toa-than-phap","name":"Tỏa Thần pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp — Hồn phiên","phamCap":"Bí pháp tế luyện Thập Ức Tôn Hồn Phiên (Luyện Hồn Tông)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Phương pháp tế luyện Thập Ức Tôn Hồn Phiên — Độn Thiên ghi trong ngọc giản tặng VL. Trong Luyện Hồn tông toàn bộ tính cả VL chỉ có 2 người biết. Khi vận chuyển: Nguyên Thần lóe vô số tia sáng yêu dị, khiến hồn phách hỗn loạn kêu chói tai tản ra, thu phục 12 hồn phách vàng tím (Anh Biến kỳ) trong hồn hải.","detail":"Công dụng: tế luyện Thập Ức Tôn Hồn Phiên từng bước — (1) chui Nguyên Thần vào hồn phiên, đối mặt vô số hồn phách tấn công; (2) vận chuyển Tỏa Thần thuật, Nguyên Thần phát tia sáng yêu dị xua tản hồn phách; (3) thu phục hồn phách cốt lõi (12 vàng tím = Anh Biến kỳ) — đây là linh hồn của phiên; (4) khi 12 hồn phách bái VL, toàn bộ linh lực hóa thành luồng khí đen gắn kết tạo cây hồn phiên hư ảo 3 trượng; VL nắm lấy = điều khiển Thập Ức Hồn Phiên. Trong Luyện Hồn tông: chỉ có Độn Thiên + VL (người thứ 2) biết pháp này. Bí pháp nằm trong ngọc giản Độn Thiên tặng kèm hồn phiên bản sao (@c0369). VL hoàn thành tế luyện trong vòng tròn đỏ Luyện Hồn phong, 12 hồn phách tử kim vái rồi quy phục (@c0370).","nguon":["@c0369","@c0370","@c0376","@c0377","@c0387"]},{"id":"tran-phap-dinh-vi","name":"Trận pháp định vị","cn":"","loai":"tran-phap","loaiLabel":"Trận pháp","phamCap":"Bí trận đối phó thiên phú thần thông","hePhai":"Luyện Hồn Tông (gốc Độn Thiên) + cải tiến VL","soHuu":["vuong-lam"],"blurb":"Trận pháp chuyên đối phó thiên phú thần thông truyền tống của lão tổ Cự Ma tộc. Nguyên lý: gắn sợi dây vô hình vào người dùng — dù bị truyền tống đi không bị đi quá xa + nhanh chóng xác định phương hướng trở về. Gốc từ ngọc giản Độn Thiên tặng; VL pha trộn thêm thuật cấm chế bản thân → tinh diệu hơn. Mất 3 tháng bố trí, dùng khối tiên ngọc duy trì năng lượng + vô số cấm chế bảo vệ.","detail":"Nguyên lý kỹ thuật: buộc sợi dây vô hình (cấm chế) quanh người sử dụng; khi bị thiên phú thần thông truyền tống, sợi dây giữ lại — hạn chế khoảng cách bị tống, đồng thời cung cấp phương hướng để trở về. Độn Thiên thiết kế ban đầu dành riêng cho lão tổ Cự Ma tộc — lão đây là người duy nhất mà Độn Thiên biết có thiên phú thần thông loại này. VL nghiên cứu gốc rồi pha trộn cấm chế riêng → tinh vi hơn. Bố trí tại sơn cốc bí ẩn biên giới Cự Ma tộc: mất 3 tháng, đặt khối tiên ngọc duy trì năng lượng + vô số cấm chế bảo vệ xung quanh. (@c0370)","nguon":["@c0370"]},{"id":"co-than-rong-nhat-tu","name":"Cổ Thần rống — nhất tự ra oai","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Cổ Thần","phamCap":"Thần thông Cổ Thần đặc hữu","hePhai":"Cổ Thần","soHuu":["vuong-lam"],"blurb":"Thần thông VL lần đầu toàn lực thi triển sau khi bổn tôn + phân thân dung hợp: thốt một chữ (Biến! / Phong!) — tiếng hét Cổ Thần rống lên, thanh âm long trời lở đất. Uy lực: mây biến mất, mặt đất xé rách, vết nứt không gian xuất hiện, 17 tu sĩ Hóa Thần phun máu lui lại không dám ra tay. Lý Nguyên Phong nhận xét 'chẳng kém tu sĩ Anh Biến kỳ'.","detail":"Cơ chế: khi VL thốt một chữ (thường là 'Biến!' hoặc 'Phong!'), Cổ Thần bên trong VL toàn lực rống lên — thanh âm kết hợp ý cảnh Sinh Tử + sức mạnh thân thể tam tinh Cổ Thần. Biểu hiện: (1) thanh âm long trời lở đất; (2) mây biến mất khỏi bầu trời; (3) vết nứt không gian xuất hiện; (4) mặt đất xé rách; (5) toàn bộ tu sĩ Hóa Thần trong phạm vi phun máu lui lại, không dám ra tay. Điều kiện sử dụng: VL sau khi dung hợp bổn tôn + phân thân (thân thể tam tinh Cổ Thần). Lần đầu sử dụng toàn lực @c0366 (trước đó chỉ dùng một phần). Lý Nguyên Phong — Anh Biến kỳ — nhận xét uy lực tương đương Anh Biến kỳ. Tại Cự Ma tộc, thốt 'Biến!' khiến trưởng lão biến khổng lồ 10 trượng bị Nguyên Thần chấn động nghiêng ngả (@c0370).","nguon":["@c0366","@c0370"]},{"id":"thong-thien-dai-tran","name":"Thông Thiên đại trận","cn":"","loai":"tran-phap","loaiLabel":"Trận pháp — Cự Ma tộc","phamCap":"Đại trận toàn tộc — cần cả tộc tụng Ma chú","hePhai":"Cự Ma tộc","soHuu":["cu-ma-toc"],"blurb":"Đại trận phòng thủ kiêm tấn công của Cự Ma tộc: 4 trưởng lão + thiếu tông chủ mở 12 cột sáng đen, toàn tộc đồng thanh tụng Ma chú, 12 luồng sáng đen kết hợp tấn công mục tiêu. Lão tổ (thân thể Cổ Thần tam tinh) chịu được 8 luồng; người chủ trì bị cắn trả nếu trận bị phá.","detail":"Kết cấu: 4 trưởng lão + thiếu tông chủ (5 người) cùng khai mở 12 cột sáng đen, toàn tộc nhân đồng thanh tụng Ma chú phối hợp. 12 luồng sáng đen phóng ra tấn công. Lão tổ Cự Ma tộc dùng thân thể tam tinh Cổ Thần chịu 8 luồng và đấm vỡ chúng. Người chủ trì trận bị cắn trả (nội thương) khi trận bị phá. Được sử dụng tại Chu Tước tinh để vây đánh Vương Lâm (@c0371).","nguon":["@c0371"]},{"id":"than-the-tam-tinh-co-than","name":"Thân thể tam tinh Cổ Thần","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể — Cổ Thần","phamCap":"Cổ Thần cấp — tam tinh","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thân thể đặc hữu của Cổ Thần tam tinh: phình to hơn 10 trượng, mi tâm sáng 3 điểm tím, đấm vỡ luồng sáng đen. Vô địch về thân thể trên Chu Tước tinh khi không có tu sĩ Anh Biến dùng tiên lực. Là nền tảng sức mạnh thể xác của Vương Lâm.","detail":"Biểu hiện: thân to hơn 10 trượng, 3 điểm sáng tím ở mi tâm, sức mạnh thể xác áp đảo. Lần đầu toàn lực thi triển tại trận Cự Ma tộc (@c0371): chịu 8 luồng Thông Thiên đại trận và đấm vỡ trực tiếp. Đối đầu với lão tổ Cự Ma tộc (cũng có thân thể Cổ Thần) thì khớp xương lão nứt khi giao quyền (@c0372). Lý Nguyên Phong đánh giá ngang Anh Biến kỳ. Nền tảng: tu luyện Cổ Thần quyết.","nguon":["@c0371","@c0372"]},{"id":"luyen-the-thuat-cu-ma-toc","name":"Luyện Thể thuật tộc Cự Ma","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể — Cự Ma tộc","phamCap":"Thể tu — toàn tộc tu luyện","hePhai":"Cự Ma tộc","soHuu":["cu-ma-toc"],"blurb":"Công pháp luyện thể cốt lõi của Cự Ma tộc: cả tộc chủ yếu tu luyện thể chất thay vì pháp thuật. Kết quả: thân thể cực cường, không e ngại nhiều loại pháp bảo. Lão tổ dù chỉ còn 8 thành công lực vẫn mạnh, nhưng khớp xương nứt khi giao quyền với thân thể tam tinh Cổ Thần của Vương Lâm.","detail":"Cự Ma tộc thiên về luyện thể thay vì tu luyện linh lực/pháp thuật thông thường. Biểu hiện: thân thể cực cường, có thể chống đỡ nhiều pháp bảo mà không bị thương. Giới hạn: thua kém thân thể tam tinh Cổ Thần của VL — lão tổ giao quyền bị nứt khớp dù VL chỉ đơn giản đấm trực tiếp (@c0371, @c0372).","nguon":["@c0371","@c0372"]},{"id":"hu-anh-co-than","name":"Hư ảnh Cổ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Cổ Thần hư ảnh","phamCap":"Cổ Thần cấp — thi triển qua ý cảnh","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm triệu hiện hư ảnh Cổ Thần phía sau lưng: mi tâm 3 điểm sáng tím, khí tím bao phủ. Hư ảnh có thể kích cách không — VL đánh nhẹ, hư ảnh giơ nắm tay đánh về phía địch từ xa, khiến lão tổ Cự Ma tộc phun máu. Về sau VL triển khai hư ảnh khổng lồ từ ý cảnh lôi sứ giả thiên đạo ra hư vô.","detail":"Cơ chế ban đầu (@c0372-@c0373): 3 điểm sáng tím ở mi tâm kích hoạt, khí tím bao phủ thân người, hư ảnh Cổ Thần hiện phía sau. Khi VL ra đòn, hư ảnh đồng thời ra đòn tương ứng tác động lên không gian phía trước địch — cách không va chạm. Dùng khiến lão tổ phun máu dù lão tổ đứng cách xa (@c0373). Giai đoạn nâng cao (@c0381): VL triển khai ý cảnh sinh tử hóa hư ảnh Cổ Thần khổng lồ — mang khí tức thiên đạo sứ giả, kéo sứ giả ra hư vô và đánh. Từ cổ tới kim chưa cổ thần nào nắm giữ. Hư ảnh kết hợp khí xám bức họa sinh tử.","nguon":["@c0372","@c0373","@c0381"]},{"id":"soi-to-linh-luc-troi-buoc","name":"Sợi tơ linh lực trói buộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông — trói buộc","phamCap":"Hóa Thần kỳ (Vương Lâm)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm triển khai từ hư không: vô số sợi tơ linh lực xuất hiện từ hư không hướng về trói buộc toàn thân đối thủ, hạn chế cử động.","detail":"Dùng trong trận chiến với lão tổ Cự Ma tộc tại Chu Tước tinh (@c0372). Cơ chế: VL khởi động thần thức, vô số sợi tơ linh lực từ hư không bay tới quấn chặt toàn thân lão tổ. Mục đích: hạn chế động tác để tạo điều kiện cho đòn đánh tiếp theo.","nguon":["@c0372"]},{"id":"khong-che-kiem-tien","name":"Khống chế kiếm tiên (đoạt quyền điều khiển)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — đoạt quyền","phamCap":"Hóa Thần kỳ (Vương Lâm)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm dùng ngón tay điểm về kiếm tiên đang chém mình → đoạt lấy khống chế của chủ sở hữu, buộc kiếm chuyển hướng chém ngược lại chủ.","detail":"Dùng trong trận chiến với lão tổ Cự Ma tộc (@c0373): lão tổ phóng kiếm tiên chém về phía VL, VL điểm ngón tay vào kiếm → khống chế kiếm bị đoạt, kiếm lập tức chuyển hướng chém ngược lại lão tổ. Cơ chế chi tiết không được giải thích trong nguyên tác — có thể liên quan đến thần thức cưỡng chế hoặc ý cảnh Sinh Tử.","nguon":["@c0373"]},{"id":"phap-an-trieu-di-vat","name":"Pháp ấn triệu di vật tổ tiên","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật — triệu vật cổ đại","phamCap":"Cao (Anh Biến kỳ — lão tổ tộc Cự Ma)","hePhai":"Cự Ma tộc","soHuu":["lao-to-cu-ma-toc"],"blurb":"Bí thuật đặc hữu tộc Cự Ma: lão tổ bắt quyết tạo pháp ấn lớn, quỳ bái xưng đệ tử đời thứ 67 → triệu xuất cự phủ đỏ của tổ tiên từ ngọn núi cao nhất. Di vật tổ tiên chứa vòng tuần hoàn khí đỏ và thiên uy.","detail":"Quy trình: lão tổ bắt quyết → tạo pháp ấn lớn → quỳ bái xưng đệ tử đời thứ 67 của tộc Cự Ma → triệu di vật tổ tiên (cự phủ đỏ) từ đỉnh núi cao nhất tộc Cự Ma hạ xuống (@c0373). Di vật tổ tiên là cự phủ màu đỏ — tự mọc lại cánh tay bị đứt, tăng sức chiến đấu, đòn cuối phóng tia chớp đỏ mang thiên uy. Lão tổ dùng làm vũ khí sau khi đòn thể chất thất bại.","nguon":["@c0373"]},{"id":"hac-viem-thu-thuat","name":"Hắc Viêm thú thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông — triệu thú","phamCap":"Không rõ phẩm cấp","hePhai":null,"soHuu":[],"blurb":"Thần thông triệu thú đặc biệt: dùng mộc côn đen + biển lửa đen + tiên quyết để ngưng tụ lửa thành Hắc Viêm thú — yêu thú lửa đen tự hàn gắn vết thương. Xuất hiện trong trận chiến tại Cự Ma tộc.","detail":"Quy trình thi triển: mộc côn đen dẫn biển lửa đen kết hợp tiên quyết → ngưng tụ năng lượng → Hắc Viêm thú hình thành. Đặc điểm: vết thương trên Hắc Viêm thú tự động khép lại (hàn gắn). Người dùng và phía tộc Cự Ma không rõ lai lịch, chỉ biết từ phía đối phương tham chiến (@c0373).","nguon":["@c0373"]},{"id":"tram-tinh-dao","name":"Trảm Tình đạo","cn":"","loai":"y-canh","loaiLabel":"Ý cảnh — Trảm Tình","phamCap":"Anh Biến kỳ — đạo hóa thần (Chu Vũ Thái)","hePhai":null,"soHuu":["chu-vu-thai"],"blurb":"Con đường hóa thần của Chu Vũ Thái: dưỡng dục đệ tử từ nhỏ tạo tình cảm sâu nặng, rồi tự tay giết đệ tử để lấy đau khổ mà nhập Thần. Hư ảnh đệ tử khoảng 20 tuổi quyến luyến hiện sau lưng Chu Vũ Thái trong trạng thái tâm thần bất ổn.","detail":"Cơ chế: Trảm Tình đạo yêu cầu tu sĩ trồng tình cảm thật — dưỡng dục đệ tử từ nhỏ, chăm sóc đến khi tình thầy trò sâu nặng. Sau đó tự tay giết đệ tử: khoảnh khắc cực đau này vừa trảm tình (đứt bỏ tình cảm) vừa dùng đau khổ làm nhiên liệu nhập Thần. Hư ảnh đệ tử khoảng 20 tuổi xuất hiện quyến luyến sau lưng Chu Vũ Thái trong khi ông ta tâm thần không ổn định (@c0374). Liên quan đến khái niệm Ý cảnh đã có.","nguon":["@c0374"]},{"id":"thap-uc-hon-phien-don-thon","name":"Thập ức hồn phiên — đòn Thôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phiên","phamCap":"Anh Biến kỳ (VL + Thập Ức Tôn Hồn Phiên)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Đòn tấn công hồn phách cực mạnh của Vương Lâm sử dụng Thập Ức Tôn Hồn Phiên: hô Thôn → 12 chủ hồn Anh Biến tỏa sợi tơ vàng đan lưới bao kín mục tiêu, triệu hồn phách nhảy vào vòng nuốt chửng → ép nạn nhân thành da bọc xương.","detail":"Quy trình: VL hô Thôn → Thập Ức Tôn Hồn Phiên kích hoạt → 12 chủ hồn Anh Biến phóng ra vô số sợi tơ vàng đan thành lưới bao chặt mục tiêu → hồn phách từ hồn phiên nhảy vào bên trong lưới nuốt dần hồn phách mục tiêu → thân xác nạn nhân héo rút lại thành da bọc xương. Dùng để hạ lão tổ Cự Ma tộc còn 2 thành công lực (@c0374). Đây là tên gọi cụ thể lần đầu được đặt cho đòn đánh của Hồn Phiên.","nguon":["@c0374"]},{"id":"cu-phu-do","name":"Cự phủ đỏ (di vật tổ tiên)","cn":"","loai":"phap-bao","loaiLabel":"Pháp bảo — di vật cổ đại","phamCap":"Tổ tiên Cự Ma tộc","hePhai":"Cự Ma tộc","soHuu":["lao-to-cu-ma-toc"],"blurb":"Di vật tổ tiên của tộc Cự Ma — cự phủ màu đỏ được triệu xuất bằng pháp ấn. Vòng tuần hoàn khí đỏ tăng sức chiến đấu, mọc lại cánh tay đứt; đòn cuối triệu tia chớp đỏ mang thiên uy.","detail":"Được lão tổ Cự Ma tộc triệu xuất bằng Pháp ấn triệu di vật tổ tiên (@c0373). Công năng: (1) vòng tuần hoàn khí đỏ tăng sức — hồi phục cánh tay bị Vương Lâm chặt đứt; (2) tăng mạnh sức chiến đấu tổng thể; (3) đòn cuối: triệu tia chớp đỏ mang thiên uy đánh xuống đối thủ (@c0374). Bị Thập ức hồn phiên — đòn Thôn của VL vô hiệu hóa khi lão tổ chỉ còn 2 thành công lực.","nguon":["@c0373","@c0374"]},{"id":"thien-phu-than-thong-cu-ma","name":"Thiên phú thần thông (Cự Ma tộc)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — thiên phú bẩm sinh","phamCap":"Thiên phú — tộc Cự Ma (một vài người đặc biệt)","hePhai":"Cự Ma tộc","soHuu":["thieu-tong-chu-cu-ma"],"blurb":"Thiên phú bẩm sinh hiếm có của tộc Cự Ma: tạo vòng xoáy khổng lồ trên đầu, lực hút cực mạnh có thể nhốt đối thủ đẩy vào tinh không. Nguy hiểm: nếu dùng khi chưa dung hợp thân thể hoàn toàn thì Nguyên Thần có thể vỡ nát.","detail":"Thiếu tông chủ Cự Ma tộc kích hoạt thiên phú thần thông — vòng xoáy khổng lồ xuất hiện trên đầu, lực hút mạnh đến mức có thể tống mục tiêu vào tinh không (@c0375). VL dùng trận pháp bố trí sẵn để giảm ảnh hưởng. Nguy cơ tự hại: nếu người dùng chưa dung hợp thân thể hoàn toàn mà kích hoạt, Nguyên Thần sẽ bị tổn hại nghiêm trọng, có thể vỡ nát. Bộc phát trong tình huống cận chiến cùng cực.","nguon":["@c0375"]},{"id":"tran-phap-chong-vong-xoay","name":"Trận pháp chống vòng xoáy","cn":"","loai":"tran-phap","loaiLabel":"Trận pháp — bố trí sẵn","phamCap":"Hóa Thần kỳ (VL tự bố trí)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Trận pháp Vương Lâm bố trí trước trong sơn cốc để đối phó với thiên phú thần thông (vòng xoáy) của tộc Cự Ma. Khi kích hoạt, giảm thiểu lực hút của vòng xoáy, ngăn VL bị tống vào tinh không.","detail":"VL dự đoán trước nguy cơ thiên phú thần thông của Cự Ma tộc, sắp xếp trận pháp bố trí sẵn trong sơn cốc (@c0375). Khi thiếu tông chủ kích hoạt vòng xoáy khổng lồ, trận pháp VL cũng đồng thời kích hoạt để chống lại lực hút. Giúp VL không bị tống vào tinh không. Có thể kết hợp từ kiến thức trận pháp thu được từ Độn Thiên.","nguon":["@c0375"]},{"id":"y-canh-me-hoac-mi-co","name":"Ý cảnh mê hoặc (Mị Cơ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — ý cảnh mê hoặc","phamCap":"Cực cao — mê hoặc cả tu sĩ Anh Biến","hePhai":null,"soHuu":["mi-co"],"blurb":"Loại ý cảnh đặc hữu ẩn trong hồn phách Mị Cơ — mê hoặc vạn vật kể cả tu sĩ Anh Biến kỳ. Chỉ người nắm Tỏa Thần thuật mới miễn nhiễm hoàn toàn.","detail":"Ý cảnh mê hoặc của Mị Cơ được nhắc đến (@c0376): loại ý cảnh này ẩn trong hồn phách, có thể mê hoặc vạn vật kể cả tu sĩ Anh Biến kỳ — mức độ uy lực rất cao. Chỉ người tu Tỏa Thần thuật (vạn tà bất xâm) mới có thể hoàn toàn miễn nhiễm. VL dùng Tỏa Thần thuật để chống lại.","nguon":["@c0376"]},{"id":"phu-the-nguyen-anh","name":"Phụ thể Nguyên Anh","cn":"","loai":"than-thong","loaiLabel":"Thần thông — hồn phách phụ thể","phamCap":"Nguyên Anh kỳ (Lý Mộ Uyển)","hePhai":null,"soHuu":["ly-mo-uyen"],"blurb":"Cơ chế Nguyên Anh Lý Mộ Uyển phụ thể vào thân xác đứa bé sơ sinh (Chu Như): không thay thế hoàn toàn hồn phách của đứa bé ngay lập tức, mà từ từ cắn nuốt và thay thế dần. Khi Nguyên Anh thức tỉnh đầy đủ mới chiếm hoàn toàn.","detail":"Lý Mộ Uyển (Nguyên Anh kỳ) thực hiện phụ thể vào thân xác Chu Như (đứa bé) sau khi chết (@c0377). Đặc điểm kỳ lạ: Nguyên Anh phụ thể nhưng không thay thế hết hồn phách bản gốc của đứa bé — hai hồn phách cùng tồn tại, Nguyên Anh LMU dần cắn nuốt hồn phách đứa bé. Khi Nguyên Anh thức tỉnh hoàn toàn mới chiếm hữu toàn bộ. Trạng thái hiện tại: đang ngủ đông chờ thức tỉnh. VL nhận biết tình trạng này (@c0377).","nguon":["@c0377"]},{"id":"di-nang-cop-tim","name":"Lực lượng kỳ dị cọp tím (Tiểu Tử)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — yêu thú dị năng","phamCap":"Tương đương Trúc Cư hậu kỳ","hePhai":null,"soHuu":["tieu-tu-cop-tim"],"blurb":"Dị năng của yêu thú cọp tím (Tiểu Tử) nuôi bởi Vương Lâm: khi rống lên, cát chạy đá bay xung quanh. Tu vi tương đương Trúc Cư hậu kỳ.","detail":"Tiểu Tử — yêu thú cọp tím của Vương Lâm — khi rống lên tạo ra lực lượng kỳ dị khiến cát chạy đá bay trong bán kính xung quanh (@c0378). Tu vi ước tính Trúc Cư hậu kỳ. Biểu hiện đặc thù của dị năng thiên phú yêu thú — không phải pháp thuật tu luyện thông thường.","nguon":["@c0378"]},{"id":"bi-thuat-chuyen-hoa-tu-si","name":"Bí thuật chuyển hóa tu sĩ (Tiên Di tộc)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật — hiến tế tập thể","phamCap":"Tuyệt mật — toàn tộc hi sinh","hePhai":"Tiên Di tộc","soHuu":["tien-di-toc"],"blurb":"Bí thuật hiến tế tập thể của Tiên Di tộc: hi sinh lượng lớn tộc nhân để chuyển hóa một người thành tu sĩ. Đã dùng để chuyển hóa chín người, hiện 5 đã lộ diện và 4 còn ẩn.","detail":"Cơ chế: toàn tộc (hoặc đa số tộc nhân) hi sinh tập thể để cung cấp năng lượng chuyển hóa một cá nhân thành tu sĩ — cách duy nhất Tiên Di tộc (không có căn cơ tu luyện bình thường) có thể sinh ra tu sĩ. Đã thực hiện 9 lần: hiện 5 tu sĩ đã lộ diện, 4 còn ẩn (@c0379, @c0380). Sứ giả thiên đạo nghi ngờ/điều tra sự tồn tại của những tu sĩ này.","nguon":["@c0379","@c0380"]},{"id":"luan-hoi-chi-luc","name":"Luân hồi chi lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông — thiên đạo","phamCap":"Thiên đạo cấp — sứ giả thiên đạo","hePhai":null,"soHuu":["su-gia-thien-dao"],"blurb":"Lực lượng thiên đạo do sứ giả thiên đạo vận dụng: ngưng tụ thành thiên lao trói buộc toàn thân Vương Lâm bất động, không thể cử động hay dùng pháp thuật.","detail":"Sứ giả thiên đạo vận dụng luân hồi chi lực — năng lượng mang bản chất thiên đạo — ngưng tụ thành hình thức thiên lao (nhà lao thiên đạo) trói buộc toàn thân VL (@c0380). Khi bị thiên lao trói: VL không thể cử động, pháp thuật bị phong tỏa. VL phá giải bằng cách triển khai sinh tử ý cảnh — hư ảnh Cổ Thần khổng lồ kéo sứ giả ra hư vô (@c0381).","nguon":["@c0380","@c0381"]},{"id":"van-cau","name":"Vân cầu","cn":"","loai":"than-thong","loaiLabel":"Thần thông — điện lực","phamCap":"Hóa Thần kỳ (VL sau đột phá Anh Biến)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Cầu mây to như nắm tay tràn đầy điện mang — thần thông Vương Lâm tạo ra sau khi đột phá Hóa Thần kỳ. Uy lực đủ phá hủy toàn bộ tu sĩ Hóa Thần kỳ trong phạm vi.","detail":"VL tạo vân cầu (cầu mây điện) to bằng nắm tay, bên trong tràn điện mang (@c0382). Uy lực được đánh giá: đủ phá hủy hết thảy tu sĩ Hóa Thần kỳ. Dùng sau khi VL đột phá lên Hóa Thần kỳ nhờ sinh tử ý cảnh đạt đại viên mãn.","nguon":["@c0382"]},{"id":"anh-bien-co-che-dot-pha","name":"Anh Biến — cơ chế đột phá","cn":"","loai":"khai-niem","loaiLabel":"Khái niệm tu luyện — Anh Biến","phamCap":"Trên Hóa Thần kỳ","hePhai":null,"soHuu":[],"blurb":"Cảnh giới Anh Biến: ý cảnh thực chất hóa, hấp thu tiên lực. Hai con đường đột phá: (1) bài trừ hoàn toàn linh lực cũ; (2) luyện hóa linh lực thành tiên lực. Cần tiên ngọc gấp vạn lần so với dưới.","detail":"Anh Biến được giải thích cơ chế (@c0383): ý cảnh từ Hóa Thần kỳ phải được thực chất hóa, đồng thời hấp thu tiên lực. Hai phương thức đột phá: (1) bài trừ linh lực — xóa bỏ hoàn toàn linh lực cũ trước khi chuyển sang tiên lực; (2) luyện hóa linh lực — chuyển đổi dần linh lực thành tiên lực mà không bài trừ. Giai đoạn tiếp theo: Vấn Đỉnh kỳ (cần tiên ngọc gấp vạn lần so với Anh Biến).","nguon":["@c0383"]},{"id":"van-dinh-ky","name":"Vấn Đỉnh kỳ","cn":"","loai":"khai-niem","loaiLabel":"Khái niệm tu luyện — Vấn Đỉnh","phamCap":"Trên Anh Biến","hePhai":null,"soHuu":[],"blurb":"Cảnh giới tu luyện trên Anh Biến kỳ — cần tiên ngọc gấp vạn lần so với Anh Biến. Đệ tứ chủ hồn (Thập Ức Tôn Hồn Phiên) có thể đấu với tu sĩ Vấn Đỉnh kỳ. Hồn phách Vấn Đỉnh là sản phẩm của Dung hợp hồn phiên.","detail":"Vấn Đỉnh kỳ được nhắc đến như cảnh giới cao hơn Anh Biến (@c0383): (1) tiêu hao tiên ngọc gấp vạn lần Anh Biến; (2) đệ tứ chủ hồn Thập Ức Tôn Hồn Phiên đủ uy lực khiến Vấn Đỉnh Hậu Kỳ kiêng kị (@c0390); (3) Hồn phách Vấn Đỉnh là sản phẩm khi Dung hợp đủ hồn phách Anh Biến — một nén hương đủ đấu Vấn Đỉnh tu sĩ (@c0390). Đây là mục tiêu tu luyện giai đoạn sau của VL.","nguon":["@c0383","@c0390"]},{"id":"giai-phong-an-ky-uc","name":"Giải phong ấn ký ức kiếp trước","cn":"","loai":"than-thong","loaiLabel":"Thần thông — giải phong ấn","phamCap":"Hóa Thần kỳ trở lên (VL)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm dùng cách không điểm mi tâm người khác để đánh tan phong ấn ký ức kiếp trước, giải phóng ký ức bị phong ấn.","detail":"VL cách không điểm mi tâm của mục tiêu, phóng lực lượng đánh tan phong ấn ký ức kiếp trước đang giam giữ bên trong (@c0384). Sau khi phong ấn tan: mục tiêu nhớ lại ký ức kiếp trước đầy đủ. Cơ chế liên quan đến thần thức và hồn phách — VL có thể thực hiện nhờ tu vi và kinh nghiệm hồn phách từ Luyện Hồn Tông.","nguon":["@c0384"]},{"id":"cuc-canh","name":"Cực Cảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông — tuyệt học","phamCap":"Anh Biến kỳ (VL)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Một tia Cực do Thanh Thủy đưa ra được ẩn trong lực lượng công kích dòng xoáy. Nó góp phần xuyên phá bức tường không gian giữa La Thiên và Liên Minh. (+) Tuyệt học của Vương Lâm — một tia Cực Cảnh lưu lại trong ngọc giản, đủ sức khiến tu sĩ Nguyên Anh kỳ tất vong khi gặp phải. [CAN-SOAT-GOP]","detail":"Vương Lâm lưu một tia Cực Cảnh vào ngọc giản bảo hộ của Vương Thức tộc (@c0385) — dùng làm bảo bối phòng thân cho người thân. Uy lực: bất kỳ tu sĩ Nguyên Anh kỳ nào chạm phải sẽ tất vong (không thể chống đỡ). Chi tiết cơ chế Cực Cảnh không được giải thích đầy đủ trong nguyên tác các chương này.","nguon":["@c0385","@c0828"]},{"id":"phu-long-thuat-chu","name":"Phù long (Thuật Chú sư)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Thuật Chú Sư Tiên Di","phamCap":"Lục diệp Thuật Chú Sư Tiên Di tộc","hePhai":"Tiên Di tộc","soHuu":["thuat-chu-su-tien-di"],"blurb":"Thần thông đặc hữu Thuật Chú Sư Tiên Di tộc: phù văn trên thân rời thân sống dậy, bay lên hóa thành rồng phù văn bay múa — vũ khí/phòng thủ đặc thù.","detail":"Thuật Chú Sư Lục diệp Tiên Di tộc kích hoạt thần thông: phù văn từng khắc trên thân người tự rời khỏi da thịt, sống dậy như sinh vật, hóa thành rồng phù văn bay lượn và tấn công/bảo vệ (@c0385). Liên quan đến hệ thống phù văn thuật chú của Tiên Di tộc.","nguon":["@c0385"]},{"id":"phu-hieu-khai-bao","name":"Phù hiệu khai bảo (Vương Thức tộc)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật — di huấn tộc","phamCap":"Di huấn tộc Vương Thức","hePhai":"Vương Thức tộc","soHuu":["vuong-thuc-toc"],"blurb":"Di huấn của Vương Thức tộc: cắn lưỡi lấy máu bản thân, vẽ phù hiệu đặc biệt lên ngăn bí mật để mở ngọc giản chứa bảo vật của tộc.","detail":"Quy trình: cắn lưỡi → lấy máu tươi → vẽ phù hiệu đặc biệt lên ngăn bí mật → ngăn mở, lộ ra ngọc giản chứa bảo vật của Vương Thức tộc (trong đó có tia Cực Cảnh VL lưu lại) (@c0385). Dùng huyết mạch làm chìa khóa xác thực — chỉ người trong tộc Vương Thức mới có thể khai mở.","nguon":["@c0385"]},{"id":"phu-bao-tuong-go","name":"Phù bạo (tượng gỗ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — kích hoạt pháp bảo","phamCap":"Anh Biến kỳ (VL điều khiển)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm dùng để kích hoạt tượng gỗ chiến đấu: quát lệnh Phù bạo → tượng gỗ hiện phù văn tự bạo thành đòn tấn công cực mạnh; VL nén giam thành hình cầu để kiểm soát hướng phát nổ.","detail":"Cơ chế: VL hét khẩu lệnh Phù bạo → tượng gỗ kích hoạt phù văn → tự bùng nổ tạo đòn tấn công mạnh. VL thêm bước kiểm soát: giam nén năng lượng bùng nổ thành hình cầu → sau đó mới giải phóng định hướng vào mục tiêu (@c0386). Kết hợp với hệ thống tượng gỗ VL đã tu luyện từ trước.","nguon":["@c0386"]},{"id":"quang-quyen-hut","name":"Quang quyển Hút","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Anh Biến VL","phamCap":"Anh Biến kỳ (VL)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Thần thông Vương Lâm sau khi đột phá Anh Biến: triệu mây lớn tập hợp xung quanh đối thủ thành quang quyển cự đại rồi nén co rút, áp lực cực lớn đè ép địch thành huyết nhục.","detail":"VL kích hoạt sau khi đột phá Anh Biến (@c0386): triệu mây khổng lồ → mây tụ lại xung quanh đối thủ thành quang quyển cự đại → quang quyển co nén, áp lực tăng dần → mục tiêu bị ép thành huyết nhục. Dùng để tiêu diệt Lục diệp Thuật Chú Sư Tiên Di tộc.","nguon":["@c0386"]},{"id":"nam-phu-van-xam","name":"Năm phù văn xám","cn":"","loai":"than-thong","loaiLabel":"Thần thông — phù văn thuật chú","phamCap":"Anh Biến kỳ (VL sau đột phá)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Năm đoàn khí xám / phù văn xám xuất hiện khi Vương Lâm đột phá Anh Biến, ẩn trong huyệt đạo. Mang khí tức của các thuật chú sư lục diệp Tiên Di tộc đã bị VL tiêu diệt.","detail":"Khi VL đột phá Anh Biến, năm đoàn khí xám tự xuất hiện ẩn trong huyệt đạo (@c0386). Nguồn gốc: mang khí tức thuật chú sư lục diệp đã giết — có thể là dạng thần thông/kinh nghiệm chiến đấu được VL hấp thu từ kẻ địch đã tiêu diệt. Chi tiết cơ chế và công dụng chưa được triển khai rõ trong nguyên tác các chương này.","nguon":["@c0386"]},{"id":"thuc-vat-sau-la-luc-diep","name":"Thực vật sáu lá (Lục diệp Thuật Chú Sư)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Thuật Chú Sư Tiên Di","phamCap":"Lục diệp Thuật Chú Sư Tiên Di tộc","hePhai":"Tiên Di tộc","soHuu":["thuat-chu-su-tien-di"],"blurb":"Gốc thực vật sáu lá biểu trưng cấp bậc lục diệp Thuật Chú Sư Tiên Di tộc — có thể phun ra từ mi tâm, tạo hàng rào phòng thủ hoặc phản kích đối phương.","detail":"Thuật Chú Sư Lục diệp Tiên Di tộc phun gốc thực vật sáu lá ra từ mi tâm — biểu tượng cấp bậc đồng thời là vũ khí/phòng thủ (@c0386). Gốc thực vật phòng thủ/phản kích: khi đối thủ tấn công mi tâm, gốc sáu lá phun ra chặn. Bị Quang quyển Hút của VL đè bẹp.","nguon":["@c0386"]},{"id":"khe-nut-khong-gian","name":"Khe nứt không gian (VL tạo)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — không gian","phamCap":"Anh Biến kỳ (VL)","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Vương Lâm xé khe nứt không gian cự đại để chặn đường thoát của địch — khe nứt lớn đến mức bịt kín hướng trốn thoát.","detail":"VL tạo khe nứt không gian cự đại chặn đường trốn thoát của Lục diệp Thuật Chú Sư Tiên Di tộc (@c0386). Kỹ thuật xé không gian ở mức Anh Biến kỳ — quy mô lớn hơn và chủ động hơn so với giai đoạn trước.","nguon":["@c0386"]},{"id":"tran-phap-thien-dao-tong","name":"Trận pháp Thiên Đạo tông","cn":"","loai":"tran-phap","loaiLabel":"Trận pháp — phong tỏa","phamCap":"Ngăn tu sĩ Hóa Thần kỳ, chỉ Anh Biến phá giải","hePhai":null,"soHuu":["vuong-lam"],"blurb":"Trận pháp Vương Lâm bố trí tại khu vực Thiên Đạo tông để ngăn cản tu sĩ Hóa Thần kỳ xâm nhập. Chỉ có tu sĩ Anh Biến kỳ mới có đủ năng lực phá giải.","detail":"VL bố trí trận pháp tại khu vực Thiên Đạo tông để bảo vệ (@c0387). Tính năng: ngăn hoàn toàn tu sĩ Hóa Thần kỳ — chỉ Anh Biến kỳ mới có thể phá giải. Bảo vệ cấm địa hoặc vị trí quan trọng liên quan Tỏa Thần thuật.","nguon":["@c0387"]},{"id":"kiem-quyet-cu-phu","name":"Kiếm quyết Cự Phú","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết — di tích","phamCap":"Di tích kiếm đạo tiền bối","hePhai":"Hằng Nhạc phái","soHuu":[],"blurb":"Đạo kiếm quyết vị tiền bối Hằng Nhạc phái lưu lại trong kiếm Cự Phú — dành cho đệ tử hữu duyên. Được giấu trong kiếm Cự Phú như một di sản kiếm đạo.","detail":"Tiền bối Hằng Nhạc phái lưu kiếm quyết vào trong thanh kiếm Cự Phú (@c0387), chỉ người hữu duyên mới nhận được. Chi tiết nội dung kiếm quyết và uy lực không được mô tả rõ trong nguyên tác chương này.","nguon":["@c0387"]},{"id":"tran-bay-tieu-ky","name":"Trận bảy tiểu kỳ","cn":"","loai":"tran-phap","loaiLabel":"Trận pháp — Độn Thiên","phamCap":"Anh Biến kỳ (Độn Thiên)","hePhai":"Luyện Hồn Tông (Độn Thiên)","soHuu":["vuong-lam","don-thien"],"blurb":"Trận pháp bảy tiểu kỳ trắng của Độn Thiên: bảy tiểu kỳ kết thành bạch mạc bao quanh Vương Lâm, tăng tốc hấp thu tiên lực và chuyển hóa linh lực thành tiên lực.","detail":"Độn Thiên dùng bảy tiểu kỳ trắng kết thành bạch mạc bao VL (@c0388): trận pháp tăng tốc quá trình hấp thu tiên lực và chuyển hóa linh lực. Hỗ trợ cho VL đang trong quá trình đột phá Anh Biến — cần lượng tiên lực lớn và ổn định. Trận pháp thuộc Độn Thiên sở hữu, truyền cho VL sử dụng.","nguon":["@c0388"]},{"id":"trung-tu-chi-thuat","name":"Trùng tu chi thuật","cn":"","loai":"cong-phap","loaiLabel":"Công pháp — tà đạo","phamCap":"Trĩ Ma Đạo","hePhai":"Trĩ Ma Đạo","soHuu":[],"blurb":"Công pháp tà đạo của Trĩ Ma Đạo: lợi dụng độc trùng trong đầm lầy để tu luyện thăng tiến. Phương pháp tu luyện đặc thù dùng trùng độc làm năng lượng.","detail":"Trùng tu chi thuật là công pháp chính của Trĩ Ma Đạo (@c0388): thay vì hấp thu linh khí/tiên lực thông thường, họ lợi dụng độc trùng trong đầm lầy. Chi tiết cơ chế không được giải thích đầy đủ trong nguyên tác.","nguon":["@c0388"]},{"id":"hon-tran-thap-tam","name":"Hồn trận thập tam","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phiên","phamCap":"Anh Biến kỳ (Độn Thiên + Thập Ức Tôn Hồn Phiên VL)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam","don-thien"],"blurb":"Trận pháp hồn phách kết hợp: Độn Thiên hô năm triệu hồn phách, mười ba chủ hồn, hiện → Luyện hồn → thập tam hồn tụ → thập tam hồn hợp nhất → ngưng tụ thành một hồn phách Vấn Đỉnh kỳ. Một nén hương đủ đấu Vấn Đỉnh tu sĩ.","detail":"Quy trình thi triển (@c0389): (1) Hô năm triệu hồn phách, mười ba chủ hồn, hiện — triệu xuất toàn bộ; (2) Luyện hồn — nung luyện; (3) Thập tam hồn tụ — mười ba chủ hồn tập hợp; (4) Thập tam hồn hợp nhất — mười ba hồn hợp lại thành một; (5) kết quả: ngưng tụ thành hồn phách Vấn Đỉnh kỳ duy nhất cực mạnh. Uy lực: một nén hương đủ đối đầu tu sĩ Vấn Đỉnh kỳ (@c0390). Thuộc thần thông Dung hợp của Thập Ức Tôn Hồn Phiên nhưng là bước cụ thể do Độn Thiên hướng dẫn VL thực hiện.","nguon":["@c0389","@c0390"]},{"id":"thuat-chu-dinh-dinh-luyen","name":"Thuật chú Định/Đỉnh/Luyện (Cửu diệp Thuật Chú Sư)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật — Cửu diệp Thuật Chú Sư","phamCap":"Cửu diệp Thuật Chú Sư Tiên Di tộc","hePhai":"Tiên Di tộc","soHuu":["thuat-chu-su-tien-di"],"blurb":"Ba thuật chú của Cửu diệp Thuật Chú Sư Tiên Di tộc: Định — dừng/cố định mục tiêu; Đỉnh — hóa năm đỉnh đồng bủa vây; Luyện — tạo lốc xoáy cắn nuốt hồn phách.","detail":"Ba thuật chú liên hoàn (@c0389): (1) Định — hét Định dừng cố định mục tiêu; (2) Đỉnh — năm đỉnh đồng xuất hiện bủa vây; (3) Luyện — tạo lốc xoáy hồn phách cắn nuốt. Mục tiêu: tấn công hồn phách mục tiêu, dùng khi đối phương đã bị định. Bị Độn Thiên + Thập Ức Tôn Hồn Phiên của VL phá giải — mười hồn phách triệu xuất khiến Cửu diệp thuật chú sư khiếp sợ rút lui.","nguon":["@c0389"]},{"id":"luc-dao-vo-hinh","name":"Lực đạo vô hình (lồng)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Thuật Chú Sư","phamCap":"Cửu diệp Thuật Chú Sư Tiên Di tộc","hePhai":"Tiên Di tộc","soHuu":["thuat-chu-su-tien-di"],"blurb":"Thuật Chú Sư Cửu diệp vỗ hư không tạo lực đạo vô hình hình thành như lồng từ trời chụp xuống bao giam mục tiêu — ngăn thoát và nén ép.","detail":"Cửu diệp Thuật Chú Sư Tiên Di tộc vỗ hư không (@c0389): lực đạo vô hình xuất hiện từ trên trời chụp xuống, hình thành như chiếc lồng cực lớn bao chụp mục tiêu. Mục đích: giam giữ, ngăn thoát, kết hợp với thuật chú Định/Đỉnh/Luyện để tấn công hồn phách. Bị hồn phách Anh Biến của Độn Thiên/VL phá giải.","nguon":["@c0389"]},{"id":"dung-hop-hon-phien","name":"Dung hợp (Thập Ức Tôn Hồn Phiên)","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phiên cốt lõi","phamCap":"Thần thông gốc của Thập Ức Tôn Hồn Phiên — bất biến","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam","don-thien"],"blurb":"Thần thông mãi mãi không đổi của Thập Ức Tôn Hồn Phiên: dung hợp các hồn phách thành một hồn phách mạnh hơn. Hồn phách Vấn Đỉnh là sản phẩm dung hợp từ hồn phách Anh Biến — một nén hương đủ đấu Vấn Đỉnh tu sĩ.","detail":"Dung hợp là thần thông căn bản và bất biến của Thập Ức Tôn Hồn Phiên (@c0390): không thể thay đổi hay nâng cấp — đây là bản chất cốt lõi của hồn phiên này. Nguyên lý: dung hợp nhiều hồn phách yếu hơn thành một hồn phách mạnh hơn tổng. Ứng dụng cao nhất: dung hợp đủ hồn phách Anh Biến → tạo thành hồn phách Vấn Đỉnh kỳ — một nén hương đủ đối chiến tu sĩ Vấn Đỉnh kỳ (@c0390). Kết hợp với Hồn trận thập tam là biểu hiện thi triển cụ thể của Dung hợp.","nguon":["@c0390"]},{"id":"de-tu-chu-hon","name":"Đệ tứ chủ hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Chủ hồn đặc biệt","phamCap":"Vấn Đỉnh Hậu Kỳ kiêng kị — mấy vạn năm chỉ xuất một lần","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam"],"blurb":"Chủ hồn thứ tư trong Thập Ức Tôn Hồn Phiên của Vương Lâm: uy lực thật sự khiến Vấn Đỉnh Hậu Kỳ kiêng kị. Mấy vạn năm chỉ xuất hiện một lần. Đang ngủ say, gần khôi phục.","detail":"Đệ tứ chủ hồn — chủ hồn thứ tư trong 13 chủ hồn Thập Ức Tôn Hồn Phiên (@c0390): được đánh giá là uy lực thật sự — cả Vấn Đỉnh Hậu Kỳ cũng phải kiêng kị. Hiếm gặp: mấy vạn năm mới xuất hiện một lần. Trạng thái hiện tại: đang ngủ say nhưng gần khôi phục. Khi thức dậy sẽ là bước ngoặt lớn về sức mạnh VL.","nguon":["@c0390"]},{"id":"muoi-chu-hon-hien","name":"Mười chủ hồn hiện","cn":"","loai":"than-thong","loaiLabel":"Thần thông — Hồn phiên","phamCap":"Anh Biến kỳ (Độn Thiên)","hePhai":"Luyện Hồn Tông","soHuu":["vuong-lam","don-thien"],"blurb":"Thần thông Độn Thiên dùng Thập Ức Tôn Hồn Phiên: hô lệnh triệu mười Anh Biến chủ hồn xuất hiện đồng loạt — uy áp khiến Cửu diệp Thuật Chú Sư Tiên Di tộc khiếp sợ lui binh.","detail":"Độn Thiên hô lệnh triệu mười Anh Biến chủ hồn của Thập Ức Tôn Hồn Phiên đồng loạt xuất hiện (@c0390): uy áp của mười Anh Biến chủ hồn cùng lúc khiến Cửu diệp Thuật Chú Sư Tiên Di tộc (vốn đang thế thượng phong với thuật chú Định/Đỉnh/Luyện) lập tức khiếp sợ và rút lui. Đây là lần đầu toàn bộ sức mạnh của hồn phiên được phô diễn đầy đủ.","nguon":["@c0390"]},{"id":"than-dao-thuat","name":"Thuật Thần Đạo","cn":"","aliases":["Thần đạo thuật","Pháp môn phân thân Thần Đạo"],"loai":"cong-phap","loaiLabel":"Công pháp — pháp môn phân thân thượng thừa","he":"Phân thân / thần đạo","capBac":"Pháp môn phân thân hạng nhất","hePhai":"Chiến Thần Điện (thủy tổ)","nguoiDung":"Vương Lâm","blurb":"Pháp môn phân thân thượng thừa Vương Lâm khắc lại từ bố trí của thủy tổ Chiến Thần Điện. Phân thân là một khối chân thân hoàn chỉnh, sinh ra không có tu vi và thọ không quá 30 năm, nhưng giữ trọn pháp thuật + trí nhớ; tu song song giúp tăng tốc, khi Kết Anh hợp nhất hai thân làm tăng xác suất đột phá. Tu luyện không khó, không liên quan tư chất.","detail":"Vương Lâm năm xưa ở sơn động sau Chiến Thần Điện nhìn ra bố trí thuật Thần Đạo của thủy tổ, dựa trí nhớ khắc lại @c0187. Là pháp môn phân thân hạng nhất có đủ đại thần thông; phân thân hoàn toàn là chân thân, không mang thần thức/tu vi bản thể nhưng giữ trọn pháp thuật và trí nhớ. Kế hoạch dùng thuật này để đột phá Nguyên Anh: nuôi phân thân trong thiên nghịch không gian đạt Nguyên Anh trong 30 năm rồi dung hợp bổn tôn–phân thân, vượt thiên kiếp cực cảnh Kết Đan hậu kỳ mà không phải tán công @c0187. Phân thân Ngưng Khí kỳ được dùng để trà trộn vào lễ thu đồ Vân Thiên tông @c0188; sau khi Kết Anh thì hợp nhất với bổn tôn @c0200.","nguon":["@c0187","@c0188","@c0200"]},{"id":"te-dan-luyen-thuat","name":"Tế đan luyện thuật","cn":"","aliases":["Tế đan"],"loai":"cong-phap","loaiLabel":"Công pháp — pháp luyện đan độc đáo","he":"Luyện đan","capBac":"Không rõ phẩm cấp","hePhai":"Âu Dương Tử (Vân Thiên tông)","nguoiDung":"Âu Dương Tử","blurb":"Pháp luyện đan độc đáo do Âu Dương Tử tự sáng tạo: coi luyện đan là việc nghịch thiên nên cần tế phẩm. Dùng nhiều loại đan tứ phẩm tế luyện để ra một viên đan ngũ phẩm — xác suất tuy không cao nhưng cao hơn luyện thông thường.","detail":"Quan niệm: luyện đan là việc nghịch thiên giống nghi thức tế bái thiên địa, nhưng tế phẩm là đan dược @c0199. Cụ thể: dùng nhiều loại tứ phẩm linh đan tế luyện để ra một viên ngũ phẩm linh đan; bảy đỉnh kết vòng (sáu vây một), tế các đan vào sáu đỉnh ngoài rồi gom về đỉnh trung tâm. Khi linh lực giảm mạnh giữa chừng, Âu Dương Tử dùng thủ pháp Huyết tế (sáu đan sư tự bạo nội đan) để đẩy linh lực cực độ cứu vãn @c0199.","nguon":["@c0199"]},{"id":"u-minh-nhan","name":"U Minh nhãn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông — nhãn thuật","he":"U Minh","capBac":"Không rõ phẩm cấp","hePhai":"Âu Dương Tử (Vân Thiên tông)","nguoiDung":"Âu Dương Tử","blurb":"Thần thông của Âu Dương Tử hình thành sau khi ăn thành công U Minh đan (mười người ăn chỉ một thành, thất bại thì mù). Cho phép nhìn thấu vào trong đan đỉnh khi luyện đan và có thể đoạt tâm phồn người khác — nguyên nhân trọng yếu giúp hắn tiến xa trên đường luyện đan.","detail":"U Minh đan là đan dược quỷ dị: mười người ăn chỉ một thành công, thất bại thì mù cả hai mắt; thành công thì hình thành U Minh nhãn @c0199. Âu Dương Tử từng ăn thành công nên hai mắt loé u quang quỷ dị; sáu thuộc hạ không dám nhìn vào mắt hắn vì sợ bị đoạt tâm phồn. Khả năng nhìn thấu đan đỉnh giúp hắn kiểm soát quá trình luyện đan @c0199.","nguon":["@c0199"]},{"id":"lo-luyen-y-canh","name":"Lò luyện ý cảnh","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp — pháp đoạt ý cảnh","he":"Ý cảnh","capBac":"Không rõ phẩm cấp","hePhai":"Cấm địa Chu Tước Sơn","nguoiDung":"Liễu Mi","blurb":"Phương pháp lão tổ cấm địa Chu Tước truyền cho Liễu Mi: lưu thân ảnh vào đạo tâm đối tượng, dùng người đó làm lò luyện; khi ý cảnh của mình đại thành thì phá lò, đoạt ý cảnh của đối tượng. Lão tổ định dùng Vương Lâm làm lò luyện để Liễu Mi đoạt sinh tử luân hồi ý cảnh.","detail":"Lão tổ ra lệnh Liễu Mi xuất quan, tiếp xúc Vương Lâm, bằng mọi thủ đoạn lưu lại thân ảnh trong đạo tâm hắn, lấy VL làm lò luyện — khi ý cảnh Liễu Mi đại thành sẽ phá lò, đoạt sinh tử luân hồi ý cảnh của VL để vượt Kiền Phong trong cuộc tranh danh hiệu Chu Tước @c0341. Phương pháp tương tự cách Kiền Phong thôn phệ ý cảnh Hồng Điệp.","nguon":["@c0341"]}]};